import time
import random
import string
import threading
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs

from prometheus_client import (
    Counter,
    Histogram,
    Gauge,
    generate_latest,
    REGISTRY,
    CONTENT_TYPE_LATEST,
    CollectorRegistry,
)


# ── Core metrics ──────────────────────────────────────────────────────────────

# Counter: total requests per (user_id, session_id, path)
REQUEST_TOTAL = Counter(
    "http_requests_total",
    "Total HTTP requests by user, session, and path",
    ["user_id", "session_id", "path"],
)

# Histogram: latency per (user_id, session_id, path)
REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "Request latency in seconds by user, session, and path",
    ["user_id", "session_id", "path"],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0),
)

# Counter: errors per (user_id, session_id, path, status_code)
REQUEST_ERRORS = Counter(
    "http_request_errors_total",
    "Total HTTP request errors by user, session, path, and status code",
    ["user_id", "session_id", "path", "status_code"],
)

# Gauge: in‑flight requests per (user_id, session_id, path)
REQUEST_IN_PROGRESS = Gauge(
    "http_requests_in_progress",
    "In-progress HTTP requests by user, session, and path",
    ["user_id", "session_id", "path"],
)

# ── Per-unique-(user, path) dynamic metrics ──────────────────────────────────

# A lock-protected registry of dynamically created per-user-path counters
_dynamic_lock = threading.Lock()
_dynamic_counters: dict[tuple[str, str], Counter] = {}


def get_or_create_user_path_counter(user_id: str, path: str) -> Counter:
    """Return (and lazily create) a dedicated counter for a unique user+path."""
    key = (user_id, path)
    if key not in _dynamic_counters:
        with _dynamic_lock:
            if key not in _dynamic_counters:
                safe_user = user_id.replace("-", "_").replace(".", "_")
                safe_path = (
                    path.strip("/")
                    .replace("/", "_")
                    .replace("-", "_")
                    .replace(".", "_")
                ) or "root"
                metric_name = f"user_path_requests_total__{safe_user}__{safe_path}"
                counter = Counter(
                    metric_name,
                    f"Total requests for user_id={user_id} path={path}",
                )
                _dynamic_counters[key] = counter
    return _dynamic_counters[key]


# ── Tracking store (in-memory, for demonstration) ────────────────────────────

_traffic_lock = threading.Lock()
_traffic_data: dict[tuple[str, str, str], dict] = {}


def record_traffic(user_id: str, session_id: str, path: str, latency: float, status: int):
    """Keep an in-memory summary that can be queried via /traffic_report."""
    key = (user_id, session_id, path)
    with _traffic_lock:
        if key not in _traffic_data:
            _traffic_data[key] = {
                "user_id": user_id,
                "session_id": session_id,
                "path": path,
                "count": 0,
                "total_latency": 0.0,
                "last_status": 0,
                "error_count": 0,
            }
        entry = _traffic_data[key]
        entry["count"] += 1
        entry["total_latency"] += latency
        entry["last_status"] = status
        if status >= 400:
            entry["error_count"] += 1


# ── HTTP Handler ──────────────────────────────────────────────────────────────

class MetricsHTTPHandler(BaseHTTPRequestHandler):
    """Simple HTTP handler that instruments every request."""

    # Simulated application routes
    KNOWN_ROUTES = {
        "/": "Welcome! Endpoints: /api/data, /api/users, /api/orders, /health, /metrics, /traffic_report",
        "/health": '{"status": "ok"}',
        "/api/data": '{"data": [1, 2, 3]}',
        "/api/users": '{"users": ["alice", "bob"]}',
        "/api/orders": '{"orders": []}',
    }

    def do_GET(self):
        parsed = urlparse(self.path)
        path = parsed.path
        params = parse_qs(parsed.query)

        # Extract user_id and session_id from query params or headers
        user_id = (
            params.get("user_id", [None])[0]
            or self.headers.get("X-User-Id")
            or "anonymous"
        )
        session_id = (
            params.get("session_id", [None])[0]
            or self.headers.get("X-Session-Id")
            or "no-session"
        )

        # ── Metrics endpoint (Prometheus scrape target) ───────────────────
        if path == "/metrics":
            output = generate_latest(REGISTRY)
            self.send_response(200)
            self.send_header("Content-Type", CONTENT_TYPE_LATEST)
            self.end_headers()
            self.wfile.write(output)
            return

        # ── Traffic report endpoint ───────────────────────────────────────
        if path == "/traffic_report":
            self._serve_traffic_report()
            return

        # ── Instrument the request ────────────────────────────────────────
        REQUEST_IN_PROGRESS.labels(
            user_id=user_id, session_id=session_id, path=path
        ).inc()

        start = time.time()
        try:
            status, body = self._handle_route(path)
            latency = time.time() - start

            # labelled metrics
            REQUEST_TOTAL.labels(
                user_id=user_id, session_id=session_id, path=path
            ).inc()
            REQUEST_LATENCY.labels(
                user_id=user_id, session_id=session_id, path=path
            ).observe(latency)

            if status >= 400:
                REQUEST_ERRORS.labels(
                    user_id=user_id,
                    session_id=session_id,
                    path=path,
                    status_code=str(status),
                ).inc()

            # dynamic per-user-path counter
            get_or_create_user_path_counter(user_id, path).inc()

            # in-memory traffic store
            record_traffic(user_id, session_id, path, latency, status)

            # respond
            self.send_response(status)
            self.send_header("Content-Type", "application/json")
            self.end_headers()
            self.wfile.write(body.encode())

        finally:
            REQUEST_IN_PROGRESS.labels(
                user_id=user_id, session_id=session_id, path=path
            ).dec()

    def _handle_route(self, path: str) -> tuple[int, str]:
        if path in self.KNOWN_ROUTES:
            # simulate variable latency
            time.sleep(random.uniform(0.001, 0.05))
            return 200, self.KNOWN_ROUTES[path]
        return 404, '{"error": "not found"}'

    def _serve_traffic_report(self):
        """Return a human-readable traffic report from the in-memory store."""
        with _traffic_lock:
            lines = [
                "=" * 90,
                f"{'User ID':<20} {'Session ID':<20} {'Path':<20} {'Count':>6} {'Avg Lat (ms)':>14} {'Errors':>7}",
                "-" * 90,
            ]
            for key in sorted(_traffic_data.keys()):
                d = _traffic_data[key]
                avg_lat = (d["total_latency"] / d["count"] * 1000) if d["count"] else 0
                lines.append(
                    f"{d['user_id']:<20} {d['session_id']:<20} {d['path']:<20} "
                    f"{d['count']:>6} {avg_lat:>13.2f} {d['error_count']:>7}"
                )
            lines.append("=" * 90)
        body = "\n".join(lines) + "\n"
        self.send_response(200)
        self.send_header("Content-Type", "text/plain")
        self.end_headers()
        self.wfile.write(body.encode())

    # Silence default request logging
    def log_message(self, format, *args):
        pass


# ── Simulated traffic generator ──────────────────────────────────────────────

def _random_id(length: int = 8) -> str:
    return "".join(random.choices(string.ascii_lowercase + string.digits, k=length))


def simulate_traffic(base_url: str = "http://localhost:8000", duration: int = 0):
    """
    Optionally send fake traffic to the server for demonstration.
    Set duration=0 to skip.
    """
    if duration <= 0:
        return

    import urllib.request

    users = [f"user_{i}" for i in range(5)]
    sessions = {u: _random_id(12) for u in users}
    paths = ["/", "/api/data", "/api/users", "/api/orders", "/nonexistent", "/health"]

    end_time = time.time() + duration
    while time.time() < end_time:
        user = random.choice(users)
        session = sessions[user]
        path = random.choice(paths)
        url = f"{base_url}{path}?user_id={user}&session_id={session}"
        try:
            urllib.request.urlopen(url, timeout=5)
        except Exception:
            pass
        time.sleep(random.uniform(0.05, 0.3))


# ── Main ──────────────────────────────────────────────────────────────────────

def main():
    host, port = "0.0.0.0", 8000
    server = HTTPServer((host, port), MetricsHTTPHandler)
    print(f"Server running on http://{host}:{port}")
    print(f"  Prometheus metrics → http://{host}:{port}/metrics")
    print(f"  Traffic report     → http://{host}:{port}/traffic_report")
    print(f"  Example request    → http://localhost:{port}/api/data?user_id=alice&session_id=abc123")
    print()

    # Start a background traffic simulator (30 seconds of fake traffic)
    sim_thread = threading.Thread(
        target=simulate_traffic,
        kwargs={"base_url": f"http://localhost:{port}", "duration": 30},
        daemon=True,
    )
    sim_thread.start()
    print("Background traffic simulator running for 30 s …")

    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print("\nShutting down.")
        server.shutdown()


if __name__ == "__main__":
    main()